insert into public.interview_questions (category, question, answer, question_en, answer_en) values
  ('一、BJT / MOSFET 基礎', '以下為 BJT (NPN) 的飽和 (ON) 及截止 (OFF) 條件，請填入空白處：<br><br><strong>BJT (NPN) 飽和：</strong>V<sub>BE</sub> [___], V<sub>BC</sub> [___], I<sub>B</sub> ( ___ ) I<sub>C</sub>/β<br><strong>BJT (NPN) 截止：</strong>V<sub>BE</sub> [___], V<sub>BC</sub> [___], I<sub>C</sub> ( ___ ) 0', '<strong>BJT (NPN) 飽和 (Saturation)：</strong><br><div class="formula-highlight">V<sub>BE</sub> [≥ 0.7V (順偏)], V<sub>BC</sub> [≥ 0V (順偏)]<br>I<sub>B</sub> ( &gt; ) I<sub>C</sub>/β ← 過驅動 (overdrive)，基極電流超過線性所需</div><strong>BJT (NPN) 截止 (Cutoff)：</strong><br><div class="formula-highlight">V<sub>BE</sub> [&lt; 0.7V (反偏或未達門檻)], V<sub>BC</sub> [&lt; 0V (反偏)]<br>I<sub>C</sub> ( ≈ ) 0 ← 僅有微小漏電流 I<sub>CEO</sub></div><div class="key-point">關鍵：飽和時 BE 和 BC 接面都順偏，V<sub>CE(sat)</sub> ≈ 0.2V；截止時兩接面都反偏</div>', 'Fill in BJT (NPN) saturation (ON) and cutoff (OFF) conditions:<br><br><strong>BJT (NPN) Saturation:</strong> V<sub>BE</sub> [___], V<sub>BC</sub> [___], I<sub>B</sub> ( ___ ) I<sub>C</sub>/β<br><strong>BJT (NPN) Cutoff:</strong> V<sub>BE</sub> [___], V<sub>BC</sub> [___], I<sub>C</sub> ( ___ ) 0', '<strong>BJT (NPN) Saturation:</strong><br><div class="formula-highlight">V<sub>BE</sub> [≥ 0.7V (forward)], V<sub>BC</sub> [≥ 0V (forward)]<br>I<sub>B</sub> ( > ) I<sub>C</sub>/β ← overdrive</div><strong>BJT (NPN) Cutoff:</strong><br><div class="formula-highlight">V<sub>BE</sub> [< 0.7V], V<sub>BC</sub> [< 0V (reverse)]<br>I<sub>C</sub> ( ≈ ) 0</div>'),
  ('一、BJT / MOSFET 基礎', '以下為 NMOSFET 的開啟 (ON) 及截止 (OFF) 條件，請填入空白處：<br><br><strong>MOSFET (N-Ch) 飽和/開啟：</strong>V<sub>GS</sub> ( ___ ) V<sub>TH</sub>, I<sub>D</sub> ( ___ ) 0<br><strong>MOSFET (N-Ch) 截止：</strong>V<sub>GS</sub> ( ___ ) V<sub>TH</sub>, I<sub>D</sub> ( ___ ) 0', '<strong>MOSFET (N-Ch) 開啟 (ON)：</strong><br><div class="formula-highlight">V<sub>GS</sub> ( &gt; ) V<sub>TH</sub> ← 閘極電壓超過門檻電壓，通道形成<br>I<sub>D</sub> ( &gt; ) 0 ← 汲極電流導通</div><strong>MOSFET (N-Ch) 截止 (OFF)：</strong><br><div class="formula-highlight">V<sub>GS</sub> ( &lt; ) V<sub>TH</sub> ← 閘極電壓低於門檻，通道未形成<br>I<sub>D</sub> ( = ) 0 ← 無汲極電流（僅有 pA 級漏電）</div><div class="key-point">注意：MOSFET 為電壓控制元件（閘極幾乎無電流），不同於 BJT 的電流控制</div>', 'Fill in NMOSFET ON and OFF conditions:<br><br><strong>MOSFET (N-Ch) ON:</strong> V<sub>GS</sub> ( ___ ) V<sub>TH</sub>, I<sub>D</sub> ( ___ ) 0<br><strong>MOSFET (N-Ch) OFF:</strong> V<sub>GS</sub> ( ___ ) V<sub>TH</sub>, I<sub>D</sub> ( ___ ) 0', '<div class="formula-highlight">ON: V<sub>GS</sub> (>) V<sub>TH</sub>, I<sub>D</sub> (>) 0<br>OFF: V<sub>GS</sub> (<) V<sub>TH</sub>, I<sub>D</sub> (=) 0</div>'),
  ('一、BJT / MOSFET 基礎', 'BSS138 NMOS 電路分析：Q27 的 Gate 接 5V（經 10K 電阻 R1），Drain 接 12V（經 10K 電阻 R452），Source 接 GND。Q28 的 Gate 接 Q27 的 Drain（B 點），Drain 接 5V（經 10K 電阻 R453），Source 接 GND。<br><br>當 A 點 = 5V 時，請問 <strong>B, C</strong> 兩點的電壓位準？', '<strong>分析步驟：</strong><br>1. A 點 = 5V → Q27 的 V<sub>GS</sub> = 5V - 0V = 5V &gt; V<sub>TH</sub>(≈1.5V) → <strong>Q27 導通 (ON)</strong><br>2. Q27 ON → Drain (B 點) 被拉到 GND（經 R<sub>DS(on)</sub> ≈ 數 Ω）<br><div class="formula-highlight">B 點 ≈ 0V（V<sub>DS(on)</sub> ≈ I<sub>D</sub> × R<sub>DS(on)</sub> ≈ 幾 mV，可近似為 0V）<br>I<sub>D</sub> = (12V - 0V) / 10KΩ = 1.2mA</div>3. B 點 ≈ 0V → Q28 的 V<sub>GS</sub> = 0V &lt; V<sub>TH</sub> → <strong>Q28 截止 (OFF)</strong><br>4. Q28 OFF → Drain (C 點) 被 R453 上拉到 5V<br><div class="formula-highlight">C 點 ≈ 5V（無電流流過 R453，無壓降）</div><div class="key-point">答案：B = 0V，C = 5V<br>這是一個典型的 NMOS 反相器串接（Level Shifter）電路，A=HIGH → B=LOW → C=HIGH</div>', 'BSS138 NMOS circuit: Q27 Gate=5V (via R1=10K), Drain connected to 12V (via R452=10K), Source=GND. Q28 Gate=Q27 Drain (point B), Drain connected to 5V (via R453=10K), Source=GND.<br><br>When A=5V, what are voltages at <strong>B</strong> and <strong>C</strong>?', '<div class="formula-highlight">A=5V → Q27 ON (V<sub>GS</sub>=5V>V<sub>TH</sub>) → B≈0V<br>B=0V → Q28 OFF → C≈5V (pulled up by R453)</div><div class="key-point">Answer: B = 0V, C = 5V (Inverter + Level Shifter)</div>'),
  ('一、BJT / MOSFET 基礎', '請說明 BJT 的四種工作區域（截止、主動/線性、飽和、反向主動），並寫出各區域的 V<sub>BE</sub> 和 V<sub>BC</sub> 偏壓條件。', '<table class="exam-table"><tr><th>工作區域</th><th>V<sub>BE</sub></th><th>V<sub>BC</sub></th><th>用途</th></tr><tr><td>截止 (Cutoff)</td><td>反偏 (&lt;0.7V)</td><td>反偏</td><td>開關 OFF</td></tr><tr><td>主動 (Active)</td><td>順偏 (≈0.7V)</td><td>反偏</td><td>放大器</td></tr><tr><td>飽和 (Saturation)</td><td>順偏</td><td>順偏</td><td>開關 ON</td></tr><tr><td>反向主動 (Reverse)</td><td>反偏</td><td>順偏</td><td>極少使用</td></tr></table><div class="key-point">實務關鍵：數位電路中 BJT 主要用作開關（截止↔飽和），類比電路中用作放大器（主動區）</div>', 'Explain the four operating regions of a BJT (cutoff, active, saturation, reverse-active) with V<sub>BE</sub> and V<sub>BC</sub> bias conditions.', '<table class="exam-table"><tr><th>Region</th><th>V<sub>BE</sub></th><th>V<sub>BC</sub></th><th>Use</th></tr><tr><td>Cutoff</td><td>Reverse</td><td>Reverse</td><td>Switch OFF</td></tr><tr><td>Active</td><td>Forward</td><td>Reverse</td><td>Amplifier</td></tr><tr><td>Saturation</td><td>Forward</td><td>Forward</td><td>Switch ON</td></tr><tr><td>Reverse Active</td><td>Reverse</td><td>Forward</td><td>Rarely used</td></tr></table>'),
  ('二、IO 架構與介面設計', '請畫出 IO <strong>Open-Drain</strong> 與 <strong>Push-Pull</strong> 兩種輸出架構圖，並說明各自的特點與應用場合。', '<div class="exam-diagram-box"></div><strong>Push-Pull（推挽）：</strong><br>• 由一對互補 MOSFET（PMOS 上管 + NMOS 下管）組成<br>• 輸出 HIGH = PMOS ON（接 VDD），輸出 LOW = NMOS ON（接 GND）<br>• 可主動驅動高低電平，速度快，驅動能力強<br>• 缺點：不能直接線或 (Wire-OR)，多個輸出不能並接<br><br><strong>Open-Drain（開漏）：</strong><br>• 僅有一個 NMOS 下拉管，無上拉管<br>• 輸出 LOW = NMOS ON（拉到 GND），HIGH = NMOS OFF（靠外部上拉電阻 Rp 拉到 VDD）<br>• 優點：可實現線與 (Wire-AND/OR)，支持不同電壓域（如 1.8V ↔ 3.3V）<br>• 缺點：上升沿速度受 Rp × C 限制，功耗較高（持續有上拉電流）<br><div class="key-point">應用：I2C 使用 Open-Drain（SDA/SCL 都需外部上拉）；GPIO/SPI 通常用 Push-Pull</div>', 'Draw <strong>Open-Drain</strong> and <strong>Push-Pull</strong> IO output architectures. Explain characteristics and use cases.', '<div class="exam-diagram-box"></div><strong>Push-Pull:</strong> PMOS+NMOS complementary pair. Actively drives HIGH/LOW.<br><strong>Open-Drain:</strong> NMOS only + external pull-up. Supports wire-AND, level shifting.<br><div class="key-point">I2C uses Open-Drain; SPI/GPIO typically Push-Pull</div>'),
  ('二、IO 架構與介面設計', '請畫出 <strong>I2C Bus</strong> 介面配線圖，包含 Master/Slave 架構、上拉電阻、SDA/SCL 訊號方向性。', '<div class="exam-diagram-box"></div><strong>I2C 匯流排架構要點：</strong><br>• SDA（資料）和 SCL（時鐘）都是 <strong>Open-Drain</strong> 架構，需要外部上拉電阻 Rp（典型 4.7KΩ）<br>• SCL 由 <strong>Master 驅動</strong>（單向），Slave 僅在 Clock Stretching 時才拉低 SCL<br>• SDA 為<strong>雙向</strong>：Master 寫入時 Master 驅動，Master 讀取時 Slave 驅動（ACK 也由 Slave 驅動）<br>• 可掛載多個 Slave（每個有唯一 7-bit 位址），同一匯流排最大 Cb ≤ 400pF<br><div class="formula-highlight">Rp 選擇：Rp(min) = (VDD - V<sub>OL</sub>) / I<sub>OL</sub> ≈ (3.3-0.4)/3mA ≈ 967Ω<br>Rp(max) = tr / (0.8473 × Cb) ← 由上升時間需求決定</div><div class="key-point">常見錯誤：忘記加上拉電阻、Rp 值太大（tr 太慢）或太小（I<sub>OL</sub> 超過 3mA sink 能力）</div>', 'Draw the <strong>I2C Bus</strong> wiring diagram showing Master/Slave architecture, pull-up resistors, and SDA/SCL signal directions.', '<div class="exam-diagram-box"></div>SDA/SCL are Open-Drain with pull-up Rp (4.7K typical). SCL driven by Master. SDA bidirectional.'),
  ('二、IO 架構與介面設計', 'SPI Mode 會有幾種格式？分別由哪兩個參數決定？', '<strong>SPI 有 4 種模式</strong>，由 CPOL（時鐘極性）和 CPHA（時鐘相位）兩個參數決定：<br><br><table class="exam-table"><tr><th>Mode</th><th>CPOL</th><th>CPHA</th><th>說明</th></tr><tr><td>Mode 0</td><td>0</td><td>0</td><td>閒置 LOW，第一個邊沿取樣（最常用）</td></tr><tr><td>Mode 1</td><td>0</td><td>1</td><td>閒置 LOW，第二個邊沿取樣</td></tr><tr><td>Mode 2</td><td>1</td><td>0</td><td>閒置 HIGH，第一個邊沿取樣</td></tr><tr><td>Mode 3</td><td>1</td><td>1</td><td>閒置 HIGH，第二個邊沿取樣</td></tr></table><div class="key-point">CPOL 決定 SCLK 閒置時的電平（0=LOW, 1=HIGH）<br>CPHA 決定在第幾個時鐘邊沿取樣資料（0=第一邊沿, 1=第二邊沿）<br>Master 和 Slave 必須配置相同的 Mode 才能通訊！</div>', 'How many SPI modes exist? What two parameters define them?', '<strong>4 SPI Modes</strong>, defined by CPOL (clock polarity) and CPHA (clock phase):<br><table class="exam-table"><tr><th>Mode</th><th>CPOL</th><th>CPHA</th></tr><tr><td>0</td><td>0</td><td>0</td></tr><tr><td>1</td><td>0</td><td>1</td></tr><tr><td>2</td><td>1</td><td>0</td></tr><tr><td>3</td><td>1</td><td>1</td></tr></table>'),
  ('二、IO 架構與介面設計', 'SPI 線路設計時常會串一個電阻在 Bus 上，請問：<br>1. 會串在哪一個 Pin（SCLK/MOSI/MISO/CS#）？<br>2. 靠近哪一邊（Master 還是 Slave）？<br>3. 串這電阻的目的是什麼？', '<strong>1. 串在哪個 Pin？</strong><br>通常串在 <strong>SCLK、MOSI、CS#</strong>（即 Master 輸出的訊號線上），MISO 較少串。<br><br><strong>2. 靠近哪一邊？</strong><br>串聯電阻要<strong>靠近訊號源端（Master 端）</strong>，距離越近越好。<br><br><strong>3. 目的是什麼？</strong><br><div class="formula-highlight">• 阻抗匹配 / 串聯端接 (Series Termination)：R ≈ Z₀ - R<sub>out</sub>（典型 22-33Ω）<br>• 抑制反射 (Reflection)：消除傳輸線阻抗不連續造成的振鈴<br>• 降低 EMI：減緩邊沿速率 (slew rate)，降低高頻輻射<br>• 抑制過衝/下衝 (Overshoot/Undershoot)</div><div class="key-point">設計要點：電阻值通常 22Ω~33Ω，放在 Source 端（Master）。如果走線很短（< 1cm）可以不串。<br>MISO 如果需要串，則串在 Slave 端（因為 Slave 是該訊號的 Source）。</div>', 'In SPI PCB design, a series resistor is often placed on the bus. Which pin? Near which side? What is the purpose?', '<strong>Pin:</strong> SCLK, MOSI, CS# (Master output lines)<br><strong>Position:</strong> Near source side (Master)<br><strong>Purpose:</strong> Series termination (22-33Ω) to suppress reflections, reduce EMI, and control overshoot.'),
  ('三、DC-DC 電源設計', '以下 DC-DC Buck 線路中有上管（High-Side MOSFET）和下管（Low-Side）。若下管為 MOSFET（而非二極體），請問這是 Synchronous 還是 Non-synchronous Buck Circuit？', '<div class="formula-highlight"><strong>答案：Synchronous（同步）Buck</strong></div><strong>判斷依據：</strong><br>• <strong>Synchronous Buck</strong>：上管 + 下管都是 MOSFET → 效率高（R<sub>DS(on)</sub> 壓降小）<br>• <strong>Non-synchronous Buck</strong>：上管 MOSFET + 下管為 Diode（蕭特基二極體）→ 成本低但效率較低（二極體 V<sub>F</sub> ≈ 0.3-0.5V）<br><br><div class="key-point">同步整流優勢：低輸出電壓（如 1.0V/0.8V）時效率差異更明顯。<br>缺點：需要 dead time 控制防止 shoot-through（上下管同時導通）</div>', 'A DC-DC Buck circuit has both high-side and low-side switches. If the low-side is a MOSFET (not a diode), is this Synchronous or Non-synchronous?', '<div class="formula-highlight">Answer: Synchronous Buck (both MOSFETs)</div>Non-synchronous uses diode on low side. Synchronous is more efficient at low output voltages.'),
  ('三、DC-DC 電源設計', 'Buck 電路中的 <strong>D1 二極體</strong>（或 Body Diode）的用途是什麼？', '<strong>D1（續流二極體 / Freewheeling Diode）的功能：</strong><br><br>1. <strong>續流作用</strong>：當上管 OFF 時，電感電流不能瞬間中斷（V = L × di/dt），D1 提供電流續流路徑<br>2. <strong>Dead Time 導通</strong>：同步 Buck 中，上下管切換的 Dead Time 期間，電流通過 MOSFET 的 Body Diode 續流<br>3. <strong>保護作用</strong>：防止電感反向電動勢 (Back-EMF) 損壞 MOSFET<br><div class="formula-highlight">Non-synchronous Buck：D1 = 獨立蕭特基二極體（V<sub>F</sub> ≈ 0.3V）<br>Synchronous Buck：D1 = Low-Side MOSFET 的 Body Diode（Dead Time 時導通）</div><div class="key-point">設計要點：Dead Time 越短越好（減少 body diode 導通損耗），但太短會導致 shoot-through</div>', 'What is the purpose of <strong>D1 diode</strong> (or body diode) in a Buck converter?', 'D1 provides freewheeling path for inductor current during high-side OFF period and dead-time in synchronous Buck.'),
  ('三、DC-DC 電源設計', 'DC-DC 電路中 SR2, SC3 組成的電路稱為何種電路？其功能為何？', '<div class="formula-highlight"><strong>Snubber（緩衝/吸收）電路</strong>，也稱 RC Snubber</div><strong>功能：</strong><br>1. <strong>抑制電壓尖峰 (Voltage Spike)</strong>：MOSFET 開關瞬間，寄生電感 L<sub>stray</sub> 產生 V = L × di/dt 尖峰<br>2. <strong>減少振鈴 (Ringing)</strong>：寄生 LC 諧振造成的高頻振盪<br>3. <strong>降低 EMI</strong>：吸收高頻能量，減少輻射干擾<br>4. <strong>保護 MOSFET</strong>：防止 V<sub>DS</sub> 尖峰超過 V<sub>BR(DSS)</sub> 擊穿<br><br><div class="formula-highlight">設計：R = √(L<sub>stray</sub>/C<sub>oss</sub>), C &gt; 2×C<sub>oss</sub><br>典型值：R = 1-10Ω, C = 100pF-1nF</div><div class="key-point">放置位置：盡量靠近 MOSFET 的 Drain-Source 端</div>', 'In a DC-DC circuit, what is the SR2+SC3 network called? What is its function?', '<div class="formula-highlight">Snubber (RC Snubber) circuit</div>Suppresses voltage spikes, ringing, and EMI from parasitic inductance during switching.'),
  ('三、DC-DC 電源設計', '若 5VDUAL = +5V，V_SM = +1.5V，請算出該 Buck 線路的 <strong>Duty Cycle</strong> = ?', '<strong>Buck 轉換器 Duty Cycle 公式：</strong><br><div class="formula-highlight">D = V<sub>OUT</sub> / V<sub>IN</sub> = V_SM / 5VDUAL = 1.5V / 5V = <strong>0.3（30%）</strong></div>這是理想情況（忽略二極體壓降和 MOSFET R<sub>DS(on)</sub> 損耗）。<br><br>考慮損耗的實際公式：<br><div class="formula-highlight">D = (V<sub>OUT</sub> + V<sub>DS(low)</sub>) / (V<sub>IN</sub> - V<sub>DS(high)</sub> + V<sub>DS(low)</sub>)<br>≈ (1.5 + 0.05) / (5 - 0.05 + 0.05) ≈ 0.31（31%）</div><div class="key-point">答案：D ≈ 30%（理想）/ 31%（實際）<br>意義：上管（High-Side MOSFET）在一個週期中導通 30% 的時間</div>', 'If 5VDUAL = +5V, V_SM = +1.5V, calculate the Buck converter <strong>Duty Cycle</strong>.', '<div class="formula-highlight">D = V<sub>OUT</sub>/V<sub>IN</sub> = 1.5V/5V = <strong>0.3 (30%)</strong></div>'),
  ('三、DC-DC 電源設計', '請畫出 Buck 轉換器的電流路徑圖，分別標示上管 ON 和上管 OFF 時電流的流向。', '<div class="exam-diagram-box"></div><strong>上管 ON（Phase 1）：</strong><br>電流路徑：V<sub>IN</sub> → High-Side MOSFET → 電感 L → 負載 → GND<br>電感儲能（i<sub>L</sub> 上升），di/dt = (V<sub>IN</sub> - V<sub>OUT</sub>)/L<br><br><strong>上管 OFF（Phase 2）：</strong><br>電流路徑：GND → Low-Side MOSFET/Diode → 電感 L → 負載 → GND<br>電感釋能（i<sub>L</sub> 下降），di/dt = -V<sub>OUT</sub>/L<br><div class="key-point">關鍵：電感電流連續（CCM）時兩相交替；輕載時可能進入不連續模式（DCM），電感電流降到零</div>', 'Draw the current flow paths in a Buck converter for both high-side ON and high-side OFF states.', '<div class="exam-diagram-box"></div>Phase 1: V<sub>IN</sub>→HS FET→L→Load. Phase 2: GND→LS FET→L→Load.'),
  ('四、數位邏輯閘與真值表', '請填寫以下邏輯閘的真值表：<br><br><table class="exam-table"><tr><th>A</th><th>B</th><th>AND</th><th>OR</th><th>NAND</th><th>NOR</th><th>XOR</th></tr><tr><td>0</td><td>0</td><td>?</td><td>?</td><td>?</td><td>?</td><td>?</td></tr><tr><td>0</td><td>1</td><td>?</td><td>?</td><td>?</td><td>?</td><td>?</td></tr><tr><td>1</td><td>0</td><td>?</td><td>?</td><td>?</td><td>?</td><td>?</td></tr><tr><td>1</td><td>1</td><td>?</td><td>?</td><td>?</td><td>?</td><td>?</td></tr></table>', '<table class="exam-table"><tr><th>A</th><th>B</th><th>及閘 AND</th><th>或閘 OR</th><th>反及閘 NAND</th><th>反或閘 NOR</th><th>互斥或閘 XOR</th></tr><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td></tr><tr><td>0</td><td>1</td><td>0</td><td>1</td><td>1</td><td>0</td><td>1</td></tr><tr><td>1</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td><td>1</td></tr><tr><td>1</td><td>1</td><td>1</td><td>1</td><td>0</td><td>0</td><td>0</td></tr></table><div class="formula-highlight">AND: 全1出1 | OR: 有1出1 | NAND: AND取反 | NOR: OR取反 | XOR: 不同出1</div><div class="key-point">反閘 (NOT/Inverter)：輸入 0→輸出 1，輸入 1→輸出 0<br>NAND 是萬用閘（Universal Gate），可用 NAND 組合實現所有其他邏輯閘</div>', 'Fill in the truth table for AND, OR, NAND, NOR, XOR gates.', '<table class="exam-table"><tr><th>A</th><th>B</th><th>AND</th><th>OR</th><th>NAND</th><th>NOR</th><th>XOR</th></tr><tr><td>0</td><td>0</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td></tr><tr><td>0</td><td>1</td><td>0</td><td>1</td><td>1</td><td>0</td><td>1</td></tr><tr><td>1</td><td>0</td><td>0</td><td>1</td><td>1</td><td>0</td><td>1</td></tr><tr><td>1</td><td>1</td><td>1</td><td>1</td><td>0</td><td>0</td><td>0</td></tr></table>'),
  ('四、數位邏輯閘與真值表', 'NMOS 反相器（Inverter）線路：上方接 10KΩ 上拉到 5V，NMOS Drain 接電阻，Source 接 GND。<br>當 INPUT: L = 0V, H &gt; V<sub>TH</sub> 時，請畫出 OUTPUT 波形。', '<strong>NMOS 反相器工作原理：</strong><br><div class="formula-highlight">INPUT = LOW (0V)：V<sub>GS</sub> &lt; V<sub>TH</sub> → NMOS OFF → OUTPUT 被上拉到 <strong>5V (HIGH)</strong><br>INPUT = HIGH (&gt;V<sub>TH</sub>)：V<sub>GS</sub> &gt; V<sub>TH</sub> → NMOS ON → OUTPUT 被拉到 <strong>≈ 0V (LOW)</strong></div>輸出波形與輸入<strong>反相</strong>：<br>• 輸入 LOW → 輸出 HIGH (5V)<br>• 輸入 HIGH → 輸出 LOW (≈0V, 實際為 V<sub>DS(on)</sub> ≈ 幾十 mV)<br><div class="key-point">注意：上升沿較慢（由 R×C 充電決定），下降沿較快（NMOS R<sub>DS(on)</sub> 很低）<br>這就是 Open-Drain 的基本原理！BSS138 level shifter 就是這個架構。</div>', 'NMOS inverter with 10K pull-up to 5V. Draw the OUTPUT waveform when INPUT switches L=0V, H>V<sub>TH</sub>.', '<div class="formula-highlight">IN=LOW→NMOS OFF→OUT=5V (HIGH)<br>IN=HIGH→NMOS ON→OUT≈0V (LOW)</div>Output is inverted. Rise time limited by RC, fall time fast.'),
  ('五、I2C 協議進階驗證', 'I2C Fast Mode 規格中，SCL 的 5 項關鍵時序測試為何？請列出各項的規格值。', '<table class="exam-table"><tr><th>#</th><th>測試項目</th><th>規格 (Fast Mode)</th><th>量測點</th></tr><tr><td>1</td><td>fSCL 頻率</td><td>≤ 400 kHz</td><td>SCL 週期</td></tr><tr><td>2</td><td>tLOW / tHIGH</td><td>≥ 1.3µs / ≥ 0.6µs</td><td>30%/70% VDD 交叉</td></tr><tr><td>3</td><td>tr / tf 上升/下降</td><td>20~300ns / ≤ 300ns</td><td>30%~70% VDD</td></tr><tr><td>4</td><td>tSU:DAT / tHD:DAT</td><td>≥ 100ns / 0~0.9µs</td><td>SDA vs SCL 邊沿</td></tr><tr><td>5</td><td>Start/Stop 時序</td><td>tHD:STA ≥ 0.6µs, tSU:STO ≥ 0.6µs, tBUF ≥ 1.3µs</td><td>SDA/SCL 邊沿</td></tr></table><div class="key-point">★ 第 3 項 tr/tf 是最常見的 FAIL 項目！<br>Fix: 降低 Rp（4.7K→2.2K→1K）或減少匯流排電容 Cb（縮短走線）<br>tr ≈ 0.8473 × Rp × Cb</div>', 'List the 5 key SCL timing tests for I2C Fast Mode with their spec values.', '<table class="exam-table"><tr><th>#</th><th>Test</th><th>Spec</th></tr><tr><td>1</td><td>fSCL</td><td>≤400kHz</td></tr><tr><td>2</td><td>tLOW/tHIGH</td><td>1.3/0.6µs</td></tr><tr><td>3</td><td>tr/tf ★</td><td>20-300ns</td></tr><tr><td>4</td><td>tSU/tHD:DAT</td><td>100ns/0µs</td></tr><tr><td>5</td><td>Start/Stop</td><td>≥0.6µs</td></tr></table>'),
  ('五、I2C 協議進階驗證', 'I2C 匯流排上 Cb = 200pF，目標 tr = 300ns（Fast Mode 最大值），請計算最大允許的上拉電阻 Rp 值。', '<div class="formula-highlight">tr ≈ 0.8473 × Rp × Cb<br>Rp = tr / (0.8473 × Cb)<br>Rp = 300ns / (0.8473 × 200pF)<br>Rp = 300 × 10⁻⁹ / (0.8473 × 200 × 10⁻¹²)<br>Rp = 300 / 169.46 × 10³<br><strong>Rp ≈ 1.77 KΩ（最大值）</strong></div><div class="key-point">實務選擇：使用 1.5KΩ（留餘裕）或 1.8KΩ（標準阻值）<br>同時需檢查 Rp(min) = (VDD - VOL) / IOL ≈ (3.3-0.4)/3mA = 967Ω<br>所以 Rp 範圍：967Ω ~ 1770Ω，選 <strong>1.5KΩ</strong> 較安全</div>', 'I2C bus Cb=200pF, target tr=300ns (FM max). Calculate max pull-up resistor Rp.', '<div class="formula-highlight">Rp = tr/(0.8473×Cb) = 300ns/(0.8473×200pF) ≈ <strong>1.77KΩ</strong></div>'),
  ('五、I2C 協議進階驗證', 'I2C tr (上升時間) FAIL 時，以下哪個不是正確的修正方法？<br><span class="exam-option">(A) 降低上拉電阻 Rp（4.7K→2.2K）</span><span class="exam-option">(B) 縮短 PCB 走線長度以減少 Cb</span><span class="exam-option">(C) 增加上拉電阻 Rp（2.2K→10K）</span><span class="exam-option">(D) 減少匯流排上的 Slave 數量</span>', '<div class="formula-highlight">答案：<strong>(C) 增加上拉電阻 Rp（2.2K→10K）</strong> ← 這是錯誤的！</div><strong>分析：</strong><br>• (A) ✓ 降低 Rp → 上拉電流增加 → 充電更快 → tr 減小<br>• (B) ✓ 縮短走線 → Cb 減少 → RC 時間常數變小 → tr 減小<br>• (C) ✗ 增加 Rp → 上拉電流減少 → 充電更慢 → <strong>tr 反而增大，FAIL 更嚴重！</strong><br>• (D) ✓ 減少 Slave → 匯流排負載電容 Cb 減少 → tr 減小<br><div class="key-point">記住：tr ≈ 0.8473 × Rp × Cb<br>tr FAIL = tr 太大 → 要降低 Rp 或降低 Cb</div>', 'Which is NOT a correct fix for I2C tr (rise time) FAIL?<br>(A) Reduce Rp (4.7K→2.2K)<br>(B) Shorten PCB traces<br>(C) Increase Rp (2.2K→10K)<br>(D) Reduce slave count', '<div class="formula-highlight">Answer: (C) Increasing Rp makes tr WORSE</div>'),
  ('六、綜合電路設計', '一個 LDO 輸入 5V，輸出 3.3V，負載電流 500mA。請計算 LDO 的功率損耗和效率。', '<div class="formula-highlight">P<sub>loss</sub> = (V<sub>IN</sub> - V<sub>OUT</sub>) × I<sub>LOAD</sub><br>P<sub>loss</sub> = (5V - 3.3V) × 500mA = 1.7V × 0.5A = <strong>0.85W</strong></div><div class="formula-highlight">η = V<sub>OUT</sub> / V<sub>IN</sub> × 100%<br>η = 3.3V / 5V × 100% = <strong>66%</strong></div><div class="key-point">0.85W 的損耗會產生可觀的熱量，需要考慮封裝的熱阻 θ<sub>JA</sub>。<br>若 θ<sub>JA</sub> = 50°C/W，環境 25°C → T<sub>J</sub> = 25 + 0.85×50 = 67.5°C<br>若壓差更大或電流更大，應考慮使用 Buck 轉換器替代 LDO</div>', 'LDO: V<sub>IN</sub>=5V, V<sub>OUT</sub>=3.3V, I<sub>LOAD</sub>=500mA. Calculate power loss and efficiency.', '<div class="formula-highlight">P<sub>loss</sub> = (5-3.3)×0.5 = 0.85W<br>η = 3.3/5 = 66%</div>'),
  ('六、綜合電路設計', '什麼是 ESD（靜電放電）？硬體設計中常見的 ESD 保護等級有哪些？請說明 HBM 和 CDM 模型的差異。', '<strong>ESD（Electrostatic Discharge，靜電放電）</strong>是帶電體接觸或接近導體時瞬間放電的現象。<br><br><table class="exam-table"><tr><th>模型</th><th>HBM</th><th>CDM</th></tr><tr><td>全名</td><td>Human Body Model</td><td>Charged Device Model</td></tr><tr><td>模擬</td><td>人體觸摸 IC</td><td>IC 本身帶電後放電</td></tr><tr><td>等效電路</td><td>100pF + 1.5KΩ</td><td>IC 封裝電容 (1-30pF)</td></tr><tr><td>放電時間</td><td>~150ns</td><td>~1ns（極快！）</td></tr><tr><td>典型等級</td><td>2000V (Class 2)</td><td>500V (Class C4)</td></tr><tr><td>損傷特性</td><td>接面燒毀</td><td>氧化層擊穿</td></tr></table><div class="key-point">保護設計：TVS 二極體、Guard Ring、ESD Clamp、保護二極體到 VDD/GND rail<br>PCB 層面：保護元件靠近連接器、避免長走線天線效應</div>', 'What is ESD? What are common ESD protection levels? Explain HBM vs CDM models.', '<table class="exam-table"><tr><th></th><th>HBM</th><th>CDM</th></tr><tr><td>Source</td><td>Human touch</td><td>Device charge</td></tr><tr><td>Model</td><td>100pF+1.5KΩ</td><td>Package cap</td></tr><tr><td>Duration</td><td>~150ns</td><td>~1ns</td></tr></table>'),
  ('六、綜合電路設計', '請說明 Bypass Capacitor（旁路電容）和 Decoupling Capacitor（去耦電容）的作用與放置原則。', '<strong>Bypass Capacitor（旁路電容）：</strong><br>• 將電源上的高頻雜訊旁路到 GND，提供 AC 短路路徑<br>• 典型值：100nF (0.1µF) 陶瓷電容<br><br><strong>Decoupling Capacitor（去耦電容）：</strong><br>• 為 IC 提供瞬間電流需求的本地電荷儲存<br>• 典型值：100nF + 10µF 組合（高頻+低頻覆蓋）<br><br><strong>放置原則：</strong><br><div class="formula-highlight">1. 盡量靠近 IC 電源 Pin（越近越好，走線越短越好）<br>2. 100nF 最靠近 IC，10µF 可稍遠<br>3. 電容接地 via 要短粗（降低等效串聯電感 ESL）<br>4. 每個電源 Pin 都要有獨立的去耦電容<br>5. 走線順序：電源 → 電容 → IC Pin（不能 T 型分叉）</div><div class="key-point">實務：先放 100nF 靠 Pin，再放 10µF 作為 bulk。高速設計加 1nF/10nF 覆蓋更高頻段。</div>', 'Explain the role and placement rules for bypass and decoupling capacitors.', 'Bypass caps: shunt HF noise to GND (100nF). Decoupling caps: local charge reservoir (100nF+10µF). Place as close to IC power pins as possible.'),
  ('六、綜合電路設計', '差分阻抗設計：PCB 走線寬度 W=5mil，線距 S=5mil，介電層厚度 H=4mil，εr=4.2。<br>請計算單端阻抗 Z₀ 和差分阻抗 Z<sub>diff</sub> 的近似值。', '<strong>微帶線 (Microstrip) 近似公式：</strong><br><div class="formula-highlight">Z₀ ≈ 87/√(εr+1.41) × ln(5.98×H/(0.8×W+T))<br>假設 T=1.2mil (1oz 銅)：<br>Z₀ ≈ 87/√(4.2+1.41) × ln(5.98×4/(0.8×5+1.2))<br>Z₀ ≈ 87/√5.61 × ln(23.92/5.2)<br>Z₀ ≈ 87/2.369 × ln(4.6)<br>Z₀ ≈ 36.72 × 1.526<br><strong>Z₀ ≈ 56Ω</strong></div><div class="formula-highlight">Z<sub>diff</sub> ≈ 2 × Z₀ × (1 - 0.48 × e<sup>-0.96×S/H</sup>)<br>Z<sub>diff</sub> ≈ 2 × 56 × (1 - 0.48 × e<sup>-0.96×5/4</sup>)<br>Z<sub>diff</sub> ≈ 112 × (1 - 0.48 × 0.301)<br>Z<sub>diff</sub> ≈ 112 × (1 - 0.145)<br><strong>Z<sub>diff</sub> ≈ 95.8Ω ≈ 96Ω</strong></div><div class="key-point">USB 規範需要 90Ω ±10%，此設計偏高，可適當加寬 W 或縮小 S 來調整。<br>實際設計建議使用 EDA 工具（如 Polar Si9000）精確計算。</div>', 'Differential impedance: W=5mil, S=5mil, H=4mil, εr=4.2. Calculate Z₀ and Z<sub>diff</sub>.', '<div class="formula-highlight">Z₀ ≈ 56Ω, Z<sub>diff</sub> ≈ 96Ω</div>'),
  ('六、綜合電路設計', 'PCB 設計中，高速差分對走線（如 USB/PCIe）應遵循以下哪個原則？<br><span class="exam-option">(A) 差分對走線可以分開走不同層</span><span class="exam-option">(B) 差分對中間不要鋪銅，保持空白</span><span class="exam-option">(C) 差分對要等長配對，且保持固定間距</span><span class="exam-option">(D) 差分對不需要參考平面</span>', '<div class="formula-highlight">答案：<strong>(C) 差分對要等長配對，且保持固定間距</strong></div><strong>逐項分析：</strong><br>• (A) ✗ 差分對必須在同一層，跨層會改變阻抗和耦合<br>• (B) ✗ 差分對之間通常有耦合，鋪銅與否取決於設計，但不是空白<br>• (C) ✓ 等長確保信號同時到達（減少 skew），固定間距確保阻抗一致<br>• (D) ✗ 差分對仍然需要完整的參考平面以維持阻抗控制<br><div class="key-point">差分對設計要點：等長（skew &lt; 5mil）、等距、同層、連續參考平面、避免跨分割</div>', 'For high-speed differential pairs (USB/PCIe), which rule is correct?<br>(A) Can route on different layers<br>(B) No copper between pairs<br>(C) Length-matched with fixed spacing<br>(D) No reference plane needed', '<div class="formula-highlight">Answer: (C) Length-matched with fixed spacing</div>'),
  ('七、面試實戰題', '請解釋 MOSFET 選型時需要關注的 6 個關鍵參數，並說明 FOM（品質因數）的定義。', '<table class="exam-table"><tr><th>參數</th><th>符號</th><th>意義</th></tr><tr><td>崩潰電壓</td><td>V<sub>(BR)DSS</sub></td><td>最大 Drain-Source 電壓，選 ≥ 1.2×V<sub>max</sub></td></tr><tr><td>導通電阻</td><td>R<sub>DS(on)</sub></td><td>導通時的損耗 P = I²×R<sub>DS(on)</sub></td></tr><tr><td>閘極電荷</td><td>Q<sub>g</sub></td><td>驅動閘極所需電荷量，影響開關速度</td></tr><tr><td>門檻電壓</td><td>V<sub>GS(th)</sub></td><td>MOSFET 開始導通的最低閘極電壓</td></tr><tr><td>最大電流</td><td>I<sub>D(max)</sub></td><td>連續汲極電流額定值</td></tr><tr><td>安全操作區</td><td>SOA</td><td>電壓×電流×時間的安全操作範圍</td></tr></table><div class="formula-highlight">FOM = R<sub>DS(on)</sub> × Q<sub>g</sub>（越小越好）<br>FOM 同時考慮導通損耗和開關損耗的平衡</div><div class="key-point">實務：低頻大電流 → 選 R<sub>DS(on)</sub> 小的；高頻開關 → 選 Q<sub>g</sub> 小的</div>', 'Explain 6 key MOSFET selection parameters and define FOM (Figure of Merit).', '<div class="formula-highlight">FOM = R<sub>DS(on)</sub> × Q<sub>g</sub> (lower is better)</div>'),
  ('七、面試實戰題', '什麼是 Latch-up（閂鎖效應）？發生在什麼情況下？如何預防？', '<strong>Latch-up（閂鎖效應）：</strong><br>CMOS 結構中，寄生的 PNPN 矽控整流器 (SCR/Thyristor) 被觸發後鎖定在低阻抗狀態，造成 VDD 到 GND 的大電流路徑，可能燒毀 IC。<br><br><strong>觸發條件：</strong><br>• IO Pin 電壓超出 VDD 或低於 GND（超過一個 diode drop）<br>• 大電流注入（如 ESD 事件）<br>• 電源上電順序不當（IO 電壓先於 VDD 到達）<br>• 高溫環境（降低觸發門檻）<br><br><strong>預防措施：</strong><br><div class="formula-highlight">1. Guard Ring：P+ ring 接 VDD，N+ ring 接 GND<br>2. 正確的上電順序：VDD 先於 IO 訊號<br>3. 限流電阻：IO Pin 串聯電阻限制注入電流<br>4. ESD 保護：IO Pin 加保護二極體到 VDD/GND rail<br>5. 足夠的 Substrate/Well tap 密度</div><div class="key-point">一旦 Latch-up 發生，唯一解除方法是斷電重啟！所以預防比檢測更重要。</div>', 'What is Latch-up? When does it occur? How to prevent it?', 'Latch-up: parasitic SCR in CMOS triggers and creates low-impedance VDD-GND path. Prevent with guard rings, proper power sequencing, and current limiting.'),
  ('七、面試實戰題', 'RC 低通濾波器：R=10KΩ, C=10nF。請計算截止頻率 fc 和 -3dB 時的相移。', '<div class="formula-highlight">fc = 1/(2πRC)<br>fc = 1/(2π × 10×10³ × 10×10⁻⁹)<br>fc = 1/(2π × 10⁻⁴)<br>fc = 1/(6.283 × 10⁻⁴)<br><strong>fc ≈ 1591.5 Hz ≈ 1.59 KHz</strong></div><div class="formula-highlight">在截止頻率 fc（-3dB 點）的相移：<br><strong>φ = -45°</strong></div><strong>頻率響應特性：</strong><br>• f &lt;&lt; fc：增益 ≈ 0dB，相移 ≈ 0°<br>• f = fc：增益 = -3dB，相移 = -45°<br>• f &gt;&gt; fc：增益以 -20dB/decade 下降，相移趨近 -90°<br><div class="key-point">-3dB 表示功率衰減到一半，電壓衰減到 1/√2 ≈ 0.707 倍</div>', 'RC low-pass filter: R=10KΩ, C=10nF. Calculate cutoff frequency fc and phase shift at -3dB.', '<div class="formula-highlight">fc = 1/(2πRC) = 1/(2π×10K×10nF) ≈ <strong>1.59 KHz</strong><br>Phase at fc: <strong>-45°</strong></div>'),
  ('七、面試實戰題', '請解釋 Setup Time 和 Hold Time 的定義，以及違反這些時序要求會造成什麼問題？', '<strong>Setup Time (t<sub>su</sub>)：</strong><br>資料必須在時鐘有效邊沿<strong>之前</strong>穩定的最短時間。確保暫存器能正確取樣。<br><br><strong>Hold Time (t<sub>h</sub>)：</strong><br>資料必須在時鐘有效邊沿<strong>之後</strong>繼續維持穩定的最短時間。確保取樣完成。<br><br><div class="formula-highlight">時序裕量 (Slack)：<br>Setup Slack = T<sub>clk</sub> - T<sub>co</sub> - T<sub>comb</sub> - T<sub>su</sub> ≥ 0<br>Hold Slack = T<sub>co</sub> + T<sub>comb</sub> - T<sub>h</sub> ≥ 0</div><strong>違反後果：</strong><br><div class="key-point">• 亞穩態 (Metastability)：暫存器輸出在 0 和 1 之間不確定震盪<br>• 資料錯誤：取樣到錯誤的值<br>• 系統不穩定：間歇性故障（worst case：溫度/電壓邊界條件下才出現）<br>Fix Setup Violation：降低時鐘頻率或縮短組合邏輯延遲<br>Fix Hold Violation：插入 buffer/delay cell 增加路徑延遲</div>', 'Define Setup Time and Hold Time. What happens when these timing requirements are violated?', 'Setup: data stable before clock edge. Hold: data stable after clock edge. Violations cause metastability and data errors.');
